#include <bits/stdc++.h>
using namespace std;
struct Node{
    int id,val;
};
bool operator<(Node x,Node y){
    return x.val>y.val;
}
const int N=1e5+5;
long long a[N];
bool to[N];
int n,b[N],c[N];
vector<int> g[N];
int bfs(int s){
    int ans,tot=1;
    queue<int> q;
    priority_queue<Node> ep;
    memset(to,0,sizeof(to));
    to[s]=1,q.push(s);
    ans=tot+a[s]/b[s]+(a[s]%b[s]>0)-1;
    while(q.size()){
        int f=q.front(),len=g[f].size();
        q.pop();
        for(int i=0;i<len;i++)
            if(!to[g[f][i]]){
                to[g[f][i]]=1;
                ep.push({g[f][i],a[g[f][i]]/b[g[f][i]]+(a[g[f][i]]%b[g[f][i]]>0)-1});
            }
        if(ep.empty())
            break;
        Node t=ep.top();
        ep.pop();
        tot++,ans=max(ans,tot+t.val),q.push(t.id);
    }
    return ans;
}
int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        scanf("%lld%d%d",&a[i],&b[i],&c[i]);
    for(int i=1;i<n;i++){
        int u,v;
        scanf("%d%d",&u,&v);
        g[u].push_back(v);
        g[v].push_back(u);
    }
    int ans=1e9;
    for(int i=1;i<=n;i++)
        ans=min(ans,bfs(i));
    printf("%d",ans);
    return 0;
}
